///|
pub fn planned_jobs(log : Array[String]) -> Iter[Int] {
  [|
    for value in [10, 20, 30] => {
      log.push("prepare \{value}")
      value
    }
  |]
}

///|
pub fn planned_jobs(log : Array[String]) -> Iter[Int] {
  [|
    { log.push("prepare 10"); 10 },
    { log.push("prepare 20"); 20 },
    { log.push("prepare 30"); 30 },
  |]
}

///|
pub fn planned_jobs(log : Array[String]) -> Iter[Int] {
  let prepared : Array[Int] = []
  for value in [10, 20, 30] {
    log.push("prepare \{value}")
    prepared.push(value)
  }
  [| ..prepared.iter() |]
}

///|
pub fn planned_jobs(log : Array[String]) -> Iter[Int] {
  let prepared = [10, 20, 30].iter().map(value => {
    log.push("prepare \{value}")
    value
  }).collect()
  prepared.iter()
}

///|
pub fn planned_jobs(log : Array[String]) -> Iter[Int] {
  [10, 20, 30].iter().map(value => {
    if value == 10 {
      log.push("prepare 10")
    } else if value == 20 {
      log.push("prepare 20")
      log.push("prepare 30")
    }
    value
  })
}
